  rect(-5, 9, 4, 3);
  rect(1, 9, 4, 3);
  // Boot laces
  fill(100, 75, 40);
  rect(-4, 9, 1, 1);
  rect(2, 9, 1, 1);

  // Legs — muscular
  fill(185, 150, 110);
