  rect(-6, -3, 12, 8);
  // Lighter vest overlay
  fill(110, 80, 45);
  rect(-4, -2, 8, 6);
  // Tunic skirt
  fill(100, 72, 38);
  rect(-6, 3, 12, 3);

  // Thick leather belt with buckle
  fill(70, 48, 22);
  rect(-6, 1, 12, 2);
  // Bronze buckle
  fill(175, 145, 50);
  rect(-1, 1, 2, 2);

  // Broad shoulders / bare arms — muscular, tanned
  fill(190, 155, 115);
  let armOff = w.task === 'chop' ? floor(sin(frameCount * 0.2) * 2) : 0;
  rect(-8, -1 + armOff, 2, 6);
  rect(6, -1 - armOff, 2, 6);
  // Forearm detail
  fill(180, 145, 105);
  rect(-8, 3 + armOff, 2, 2);
  rect(6, 3 - armOff, 2, 2);

  // Neck
  fill(190, 155, 115);
  rect(-3, -6, 6, 3);

  // Head — square-jawed, rugged
