function usePotion() {
  let p = state.player;
  if (p.potions <= 0 || p.hp >= p.maxHp) return;
  p.potions--;
  p.hp = min(p.maxHp, p.hp + POTION_HEAL);
  addFloatingText(w2sX(p.x), w2sY(p.y) - 25, '+' + POTION_HEAL + ' HP', '#44dd44');
  spawnParticles(p.x, p.y, 'harvest', 5);
}

function useStew() {
  let p = state.player;
  if (state.stew <= 0 || p.hp >= p.maxHp) return;
  state.stew--;
  p.hp = min(p.maxHp, p.hp + 30);
  addFloatingText(w2sX(p.x), w2sY(p.y) - 25, '+30 HP (Stew)', '#cc8844');
  spawnParticles(p.x, p.y, 'harvest', 5);
  if (snd) snd.playSFX('ding');
}

function useGarum() {
  if (state.garum <= 0) return;
  state.garum--;
  state.gold += 25;
  addFloatingText(width / 2, height * 0.35, '+25g from Garum trade', '#ddcc44');
  if (snd) snd.playSFX('ding');
}

function useHoneyedFigs() {
  if (state.honeyedFigs <= 0) return;
  state.honeyedFigs--;
  state.player.xpBoost = (state.player.xpBoost || 0) + 1;
  state.player.xpBoostTimer = 8000; // 1 game day (1440 game-min / 0.18 per frame = 8000 frames)
  addFloatingText(width / 2, height * 0.35, 'XP +15% for 1 day!', '#ffaa44');
  spawnParticles(state.player.x, state.player.y, 'divine', 5);
  if (snd) snd.playSFX('skill_unlock');
}

function useAmbrosia() {
  let p = state.player;
  if (state.ambrosia <= 0) return;
  state.ambrosia--;
  p.hp = p.maxHp;
  p.invincTimer = max(p.invincTimer, 300); // 5 seconds invuln
  addFloatingText(w2sX(p.x), w2sY(p.y) - 25, 'AMBROSIA! Full heal + invulnerable!', '#ffd700');
  spawnParticles(p.x, p.y, 'divine', 15);
  if (snd) snd.playSFX('fanfare');
}

function buyWeapon(tier) {
  let w = WEAPONS[tier];
  if (!w || state.gold < w.cost || state.player.weapon >= tier) return false;
  state.gold = max(0, state.gold - w.cost);
  state.player.weapon = tier;
  addFloatingText(width / 2, height * 0.3, w.name + ' acquired!', '#ffcc44');
  if (snd) snd.playSFX('purchase');
  return true;
}

function buyArmor(tier) {
  let a = ARMORS[tier];
  if (!a || state.gold < a.cost || state.player.armor >= tier) return false;
  state.gold = max(0, state.gold - a.cost);
  state.player.armor = tier;
  addFloatingText(width / 2, height * 0.3, a.name + ' Armor!', '#aaccff');
  if (snd) snd.playSFX('purchase');
  return true;
}

function buyPotion() {
  if (state.gold < POTION_COST) return false;
  state.gold = max(0, state.gold - POTION_COST);
  state.player.potions++;
  return true;
}

// ─── EXPEDITION UPGRADES ─────────────────────────────────────────────────
const EXPEDITION_UPGRADES = {
  workerSpeed:    { name: 'Swift Workers',    tiers: [{ gold: 50, wood: 20 },  { gold: 150, ironOre: 8 },  { gold: 300, ironOre: 15, rareHide: 5 }],  desc: 'Workers chop/build 25% faster' },
  workerCap:      { name: 'Worker Barracks',  tiers: [{ gold: 60, wood: 25 },  { gold: 180, ironOre: 12 }, { gold: 350, rareHide: 8, ancientRelic: 1 }], desc: '+1 max worker per tier' },
  dangerResist:   { name: 'Scout Network',    tiers: [{ gold: 40, wood: 15 },  { gold: 120, rareHide: 5 }, { gold: 250, ancientRelic: 2 }],             desc: 'Danger escalates slower' },
  lootBonus:      { name: 'Plunder Expertise',tiers: [{ gold: 60, wood: 20 },  { gold: 200, ironOre: 10 }, { gold: 400, titanBone: 2 }],                 desc: '+15% loot per tier' },
  soldierHP:      { name: 'Veteran Training', tiers: [{ gold: 50, ironOre: 5 },{ gold: 160, rareHide: 6 }, { gold: 320, ancientRelic: 3, titanBone: 1 }],desc: 'Soldiers start tougher' },
  expeditionTier: { name: 'Cartographer',     tiers: [{ gold: 100, ancientRelic: 2 }, { gold: 250, titanBone: 3, ancientRelic: 3 }],                      desc: 'Harder but richer expeditions' },
};


function canAffordUpgrade(cost) {
  for (let [key, val] of Object.entries(cost)) {
    if (key === 'gold' && state.gold < val) return false;
    if (key === 'wood' && state.wood < val) return false;
    if (key === 'ironOre' && state.ironOre < val) return false;
    if (key === 'rareHide' && state.rareHide < val) return false;
    if (key === 'ancientRelic' && state.ancientRelic < val) return false;
    if (key === 'titanBone' && state.titanBone < val) return false;
  }
  return true;
}

function buyExpeditionUpgrade(key) {
  let upg = EXPEDITION_UPGRADES[key];
  let tier = state.expeditionUpgrades[key] || 0;
  if (tier >= upg.tiers.length) return false;
  let cost = upg.tiers[tier];
  if (!canAffordUpgrade(cost)) return false;

  // Deduct costs
  for (let [k, v] of Object.entries(cost)) {
    if (k === 'gold') state.gold = max(0, state.gold - v);
    if (k === 'wood') state.wood -= v;
    if (k === 'ironOre') state.ironOre -= v;
    if (k === 'rareHide') state.rareHide -= v;
    if (k === 'ancientRelic') state.ancientRelic -= v;
    if (k === 'titanBone') state.titanBone -= v;
  }
  state.expeditionUpgrades[key] = tier + 1;
  addFloatingText(width / 2, height * 0.35, upg.name + ' upgraded!', '#88ccff');
  triggerScreenShake(2, 5);
  return true;
}

// ─── BOUNTY BOARD ───────────────────────────────────────────────────────
const BOUNTY_TEMPLATES = [
  { type: 'kills',     desc: 'Slay {n} wolves',        target: 3,  reward: { gold: 30 },               enemy: 'wolf' },
  { type: 'kills',     desc: 'Slay {n} boars',         target: 2,  reward: { gold: 40, ironOre: 2 },   enemy: 'boar' },
  { type: 'kills',     desc: 'Slay {n} bears',         target: 2,  reward: { gold: 50, rareHide: 2 },  enemy: 'bear' },
  { type: 'kills',     desc: 'Slay {n} dire wolves',   target: 3,  reward: { gold: 45, ironOre: 3 },   enemy: 'dire_wolf' },
  { type: 'danger',    desc: 'Reach danger level {n}',  target: 4,  reward: { gold: 60 } },
  { type: 'danger',    desc: 'Reach danger level {n}',  target: 7,  reward: { gold: 100, ancientRelic: 1 } },
  { type: 'survive',   desc: 'Survive {n} seconds',     target: 45, reward: { gold: 50, ironOre: 3 } },
  { type: 'survive',   desc: 'Survive {n} seconds',     target: 90, reward: { gold: 80, rareHide: 3 } },
  { type: 'loot',      desc: 'Collect {n} iron ore',    target: 3,  reward: { gold: 60 } },
  { type: 'loot',      desc: 'Collect {n} rare hides',  target: 2,  reward: { gold: 70 } },
  { type: 'chop',      desc: 'Chop {n} trees',          target: 8,  reward: { gold: 25, wood: 50 } },
  { type: 'build',     desc: 'Build {n} structures',    target: 2,  reward: { gold: 40, ironOre: 2 } },
  { type: 'nokill',    desc: 'Return alive (no death)',  target: 1,  reward: { gold: 35 } },
];

function generateBounties() {
  let bb = state.bountyBoard;
  if (bb.day === state.day) return; // already generated today
  bb.day = state.day;
  bb.bounties = [];
  // Pick 3 unique bounties
  let pool = [...BOUNTY_TEMPLATES];
  for (let i = 0; i < 3 && pool.length > 0; i++) {
    let idx = floor(random(pool.length));
    let tmpl = pool.splice(idx, 1)[0];
    bb.bounties.push({
      id: i,
      desc: tmpl.desc.replace('{n}', tmpl.target),
      type: tmpl.type,
      target: tmpl.target,
      enemy: tmpl.enemy || null,
      progress: 0,
      reward: { ...tmpl.reward },
      completed: false,
    });
  }
}

function updateBountyProgress(type, value, enemyType) {
  let bb = state.bountyBoard;
  for (let b of bb.bounties) {
    if (b.completed) continue;
    if (b.type === type) {
      if (type === 'kills' && b.enemy && b.enemy !== enemyType) continue;
      if (type === 'danger' || type === 'survive') {
        b.progress = max(b.progress, value); // track max reached
      } else {
        b.progress += value;
      }
      if (b.progress >= b.target && !b.completed) {
        b.completed = true;
        // Grant reward
        for (let [k, v] of Object.entries(b.reward)) {
          if (k === 'gold') state.gold += v;
          if (k === 'wood') state.wood += v;
          if (k === 'ironOre') state.ironOre += v;
          if (k === 'rareHide') state.rareHide += v;
          if (k === 'ancientRelic') state.ancientRelic += v;
          if (k === 'titanBone') state.titanBone += v;
        }
        let rewardStr = Object.entries(b.reward).map(([k, v]) => '+' + v + ' ' + k).join('  ');
        addFloatingText(width / 2, height * 0.15, 'BOUNTY COMPLETE!', '#ffdd44');
        addFloatingText(width / 2, height * 0.2, rewardStr, '#aaddff');
        triggerScreenShake(4, 10);
      }
    }
  }
}


// ─── LEGIA MILITARY SYSTEM ───────────────────────────────────────────────

function updateLegia(dt) {
  let lg = state.legia;
  if (!lg) return;
  if (lg.trainingQueue > 0 && lg.trainingTimer > 0) {
    lg.trainingTimer -= dt;
    if (lg.trainingTimer <= 0) {
      lg.recruits = min(lg.recruits + 1, lg.maxRecruits + getFactionData().recruitBonus);
      lg.trainingQueue--;
      lg.trainingTimer = lg.trainingQueue > 0 ? 300 : 0;
      addFloatingText(w2sX(lg.castrumX), w2sY(lg.castrumY) - 30, getFactionTerms().soldier + ' Ready!', '#cc4444');
      // Spawn ambient soldier entity near castrum
      let cx = lg.castrumX, cy = lg.castrumY;
      let soldierMaxHP = 60 + (state.expeditionUpgrades ? state.expeditionUpgrades.soldierHP : 0) * 20;
      lg.soldiers.push({
        x: cx + random(-30, 30), y: cy + random(-20, 20),
        hp: soldierMaxHP, maxHp: soldierMaxHP,
        facing: random() > 0.5 ? 1 : -1,
        state: 'patrol',
        patrolTimer: floor(random(60, 200)),
        targetX: cx, targetY: cy,
      });
    }
  }
}

function handleLegiaKey(k) {
  let lg = state.legia;
  if (!lg || lg.castrumLevel < 1) return false;
  // [1] Train legionary
  if (k === '1') {
    if (typeof trainUnit === 'function') {
      trainUnit('legionary');
    } else {
      if (state.gold < 20) { addFloatingText(width / 2, height * 0.3, 'Need 20 gold', '#ff6644'); return true; }
      if (state.meals < 1) { addFloatingText(width / 2, height * 0.3, 'Need 1 meal', '#ff6644'); return true; }
      if (lg.recruits + lg.trainingQueue >= lg.maxRecruits + getFactionData().recruitBonus) { addFloatingText(width / 2, height * 0.3, getFactionTerms().army + ' at capacity!', '#ff6644'); return true; }
      state.gold = max(0, state.gold - 20); state.meals = max(0, state.meals - 1);
      lg.trainingQueue++; if (lg.trainingTimer <= 0) lg.trainingTimer = 300;
      addFloatingText(width / 2, height * 0.3, 'Training ' + getFactionTerms().soldier.toLowerCase() + '...', '#cc8844');
    }
    return true;
  }
  // [2] Upgrade castrum
  if (k === '2') {
    if (lg.castrumLevel >= 5) { addFloatingText(width / 2, height * 0.3, getFactionTerms().barracks + ' at max level!', '#aaaaaa'); return true; }
    let nextLv = lg.castrumLevel + 1;
    let lvData = (typeof CASTRUM_LEVELS !== 'undefined') ? CASTRUM_LEVELS[nextLv] : null;
    if (lvData && lvData.cost) {
      let c = lvData.cost;
      if (state.gold < (c.gold || 0)) { addFloatingText(width / 2, height * 0.3, 'Need ' + c.gold + ' gold', '#ff6644'); return true; }
      if (state.stone < (c.stone || 0)) { addFloatingText(width / 2, height * 0.3, 'Need ' + c.stone + ' stone', '#ff6644'); return true; }
      if (state.ironOre < (c.ironOre || 0)) { addFloatingText(width / 2, height * 0.3, 'Need ' + c.ironOre + ' iron', '#ff6644'); return true; }
      if ((c.crystals || 0) > 0 && state.crystals < c.crystals) { addFloatingText(width / 2, height * 0.3, 'Need ' + c.crystals + ' crystals', '#ff6644'); return true; }
      state.gold = max(0, state.gold - (c.gold || 0)); state.stone = max(0, state.stone - (c.stone || 0)); state.ironOre = max(0, state.ironOre - (c.ironOre || 0)); state.crystals = max(0, state.crystals - (c.crystals || 0));
      lg.castrumLevel = nextLv;
      lg.maxRecruits = lvData.maxSoldiers;
      addFloatingText(width / 2, height * 0.3, getFactionTerms().barracks + ' upgraded to ' + getCastrumLevelName(nextLv) + '!', '#cc8844');
      if (typeof snd !== 'undefined' && snd) snd.playSFX('upgrade');
    } else {
      // Fallback for levels without CASTRUM_LEVELS data
      addFloatingText(width / 2, height * 0.3, getFactionTerms().barracks + ' at max level', '#aaaaaa');
    }
    return true;
  }
  // [3] Train archer (level 2+)
  if (k === '3' && typeof trainUnit === 'function') { trainUnit('archer'); return true; }
  // [4] Train cavalry (level 3+)
  if (k === '4' && typeof trainUnit === 'function') { trainUnit('cavalry'); return true; }
  // [5] Train siege ram (level 4+)
  if (k === '5' && typeof trainUnit === 'function') { trainUnit('siege_ram'); return true; }
  // [6] Train centurion (level 5+)
  if (k === '6' && typeof trainUnit === 'function') { trainUnit('centurion'); return true; }
  // [G] Cycle formation
  if (k === 'g' || k === 'G') {
    if (typeof cycleFormation === 'function') cycleFormation();
    return true;
  }
  return false;
}


function drawLegionPatrol() {
  let lg = state.legia;
  if (!lg || lg.castrumLevel < 1 || lg.recruits < 1) return;
  // Skip orbital circles if ambient soldier entities exist (they're drawn in Y-sorted pass)
  if (lg.soldiers && lg.soldiers.length > 0) return;
  let cx = lg.castrumX, cy = lg.castrumY;
  let count = min(lg.recruits, 6);
  let t = frameCount * 0.018;
  for (let i = 0; i < count; i++) {
    let a = t + (i / count) * TWO_PI;
    let r = 30 + i * 4;
    let sx = w2sX(cx + cos(a) * r);
    let sy = w2sY(cy + sin(a) * r);
    if (sx < -20 || sx > width + 20 || sy < -20 || sy > height + 20) continue;
    push();
    translate(sx, sy + floatOffset);
    let _m = getFactionMilitary();
    // Body — faction tunic
    fill(_m.tunic[0], _m.tunic[1], _m.tunic[2]); noStroke();
    rect(-4, -6, 8, 8);
    // Helmet — faction
    fill(_m.helm[0], _m.helm[1], _m.helm[2]);
    ellipse(0, -8, 8, 6);
    rect(-4, -10, 8, 4);
    // Shield — faction
    fill(_m.shield[0], _m.shield[1], _m.shield[2]); stroke(_m.shield[0]*0.6, _m.shield[1]*0.6, _m.shield[2]*0.6); strokeWeight(1);
    if (_m.shieldShape === 'round') ellipse(-5, -1, 7, 7);
    else rect(-7, -5, 4, 8, 1);
    // Legs
    fill(_m.legs[0], _m.legs[1], _m.legs[2]); noStroke();
    rect(-4, 2, 3, 5);
    rect(1, 2, 3, 5);
    pop();
  }
  // [E] prompt when player near gate (south side of castrum)
  let px = state.player.x, py2 = state.player.y;
  let gateY = cy + 50;
  if (dist(px, py2, cx, gateY) < 40) {
    push();
    fill(255, 255, 255, 200); noStroke();
    textAlign(CENTER, CENTER); textSize(10);
    text('[E] Enter ' + getFactionTerms().barracks, w2sX(cx), w2sY(gateY) - 20 + floatOffset);
    pop();
  }
}

function updateLegionAmbient(dt) {
  if (!state.legia || !state.legia.soldiers) return;
  let cx = state.legia.castrumX || WORLD.islandCX + 200;
  let cy = state.legia.castrumY || WORLD.islandCY + 100;
  state.legia.soldiers.forEach(s => {
    s.patrolTimer -= dt;
    if (s.state === 'idle' && s.patrolTimer <= 0) {
      s.targetX = cx + random(-50, 50);
      s.targetY = cy + random(-30, 30);
      s.state = 'patrol';
      s.patrolTimer = floor(random(120, 300));
    } else if (s.state === 'patrol') {
      let dx = (s.targetX || cx) - s.x, dy = (s.targetY || cy) - s.y;
      let d = sqrt(dx * dx + dy * dy);
      if (d < 5 || s.patrolTimer <= 0) {
        s.state = 'idle';
        s.patrolTimer = floor(random(60, 200));
      } else {
        s.x += (dx / d) * 1.2 * dt;
        s.y += (dy / d) * 0.8 * dt;
        s.facing = dx > 0 ? 1 : -1;
      }
    }
  });
}

function drawLegionAmbientSoldier(s) {
  let sx = w2sX(s.x), sy = w2sY(s.y);
  if (sx < -30 || sx > width + 30 || sy < -30 || sy > height + 30) return;
  let mil = getFactionMilitary();
  push();
  translate(sx, sy + floatOffset);
  scale(s.facing, 1);
  noStroke();
  // Shadow
  fill(0, 0, 0, 30);
  ellipse(0, 2, 10, 4);
  // Body — faction tunic
  fill(mil.tunic[0], mil.tunic[1], mil.tunic[2]);
  rect(-3, -8, 6, 10);
  // Armor plate
  fill(mil.armor[0], mil.armor[1], mil.armor[2]);
  rect(-3, -7, 6, 4);
  // Head
  fill(195, 165, 130);
  rect(-2, -12, 4, 4);
  // Helmet — faction
  fill(mil.helm[0], mil.helm[1], mil.helm[2]);
  rect(-3, -13, 6, 3);
  // Spear
  stroke(100, 80, 60);
  strokeWeight(1);
  line(3, -16, 3, 4);
  noStroke();
  // Shield — faction
  fill(mil.shield[0], mil.shield[1], mil.shield[2]);
  if (mil.shieldShape === 'round') ellipse(-4, -3, 5, 5);
  else rect(-5, -6, 2, 6);
  // Walking animation — faction leg color
  if (s.state === 'patrol') {
    let step = sin(frameCount * 0.12 + s.x) * 2;
    fill(mil.legs[0], mil.legs[1], mil.legs[2]);
    rect(-2, 2, 2, 3);
    rect(0 + step * 0.3, 2, 2, 3);
  } else {
    fill(mil.legs[0], mil.legs[1], mil.legs[2]);
    rect(-2, 2, 2, 3);
    rect(1, 2, 2, 3);
  }
  pop();
}

// ─── FOG OF WAR ─────────────────────────────────────────────────────────
const FOG_GRID = 20; // grid cell size in world units
const FOG_REVEAL_R = 5; // reveal radius in cells (~100px)

function initFogOfWar() {
  let c = state.conquest;
  let cols = ceil(c.isleRX * 2 / FOG_GRID) + 2;
  let rows = ceil(c.isleRY * 2 / FOG_GRID) + 2;
  state.fogOfWar = new Array(cols * rows).fill(0);
  state._fogCols = cols;
  state._fogRows = rows;
  state._fogOX = c.isleX - c.isleRX - FOG_GRID;
  state._fogOY = c.isleY - c.isleRY - FOG_GRID;
}

function revealFog(wx, wy) {
  if (!state._fogCols) return;
  let gx = floor((wx - state._fogOX) / FOG_GRID);
  let gy = floor((wy - state._fogOY) / FOG_GRID);
  let r = FOG_REVEAL_R;
  for (let dy = -r; dy <= r; dy++) {
    for (let dx = -r; dx <= r; dx++) {
      if (dx * dx + dy * dy > r * r) continue;
      let cx = gx + dx, cy = gy + dy;
      if (cx < 0 || cy < 0 || cx >= state._fogCols || cy >= state._fogRows) continue;
      state.fogOfWar[cy * state._fogCols + cx] = 1;
    }
  }
}

function drawFogOfWar() {
  if (!state._fogCols || !state.fogOfWar.length) return;
  let c = state.conquest;
  // Only draw fog if foggy modifier or always show partial
  let fogAlpha = state.expeditionModifier === 'foggy' ? 220 : 140;
  push();
  noStroke();
  for (let gy = 0; gy < state._fogRows; gy++) {
    for (let gx = 0; gx < state._fogCols; gx++) {
      if (state.fogOfWar[gy * state._fogCols + gx] === 1) continue;
      let wx = state._fogOX + gx * FOG_GRID;
      let wy = state._fogOY + gy * FOG_GRID;
      // Skip if outside island ellipse
      let ex = (wx + FOG_GRID / 2 - c.isleX) / c.isleRX;
      let ey = (wy + FOG_GRID / 2 - c.isleY) / c.isleRY;
      if (ex * ex + ey * ey > 1.1) continue;
      let sx = w2sX(wx), sy = w2sY(wy);
      fill(15, 20, 15, fogAlpha);
      rect(sx, sy, FOG_GRID + 1, FOG_GRID + 1);
    }
  }
  pop();
}

function drawModifierAtmosphere() {
  let mod = state.expeditionModifier;
  if (!mod || mod === 'normal') return;
  let c = state.conquest;
  let ix = w2sX(c.isleX), iy = w2sY(c.isleY);
  push();
  noStroke();
  if (mod === 'blood_moon') {
    // Red tint over everything
    fill(120, 20, 10, 25 + sin(frameCount * 0.03) * 10);
    ellipse(ix, iy, c.isleRX * 2.2, c.isleRY * 2.2);
    // Blood moon in sky
    fill(180, 40, 20, 60);
    ellipse(width * 0.8, 40, 30, 30);
    fill(200, 60, 30, 80);
    ellipse(width * 0.8, 40, 24, 24);
  } else if (mod === 'foggy') {
    // Thick fog patches
    for (let i = 0; i < 6; i++) {
      let fx = ix + sin(frameCount * 0.005 + i * 2) * c.isleRX * 0.6;
      let fy = iy + cos(frameCount * 0.004 + i * 1.7) * c.isleRY * 0.4;
      fill(160, 180, 170, 30 + sin(frameCount * 0.02 + i) * 12);
      ellipse(fx, fy, 200 + sin(i) * 60, 100 + cos(i) * 30);
    }
  } else if (mod === 'sacred') {
    // Gentle blue-white glow
    fill(100, 160, 220, 12 + sin(frameCount * 0.02) * 6);
    ellipse(ix, iy, c.isleRX * 1.8, c.isleRY * 1.8);
    // Sparkles
    if (frameCount % 20 === 0) {
      let sx = c.isleX + random(-c.isleRX * 0.7, c.isleRX * 0.7);
      let sy = c.isleY + random(-c.isleRY * 0.7, c.isleRY * 0.7);
      spawnParticles(sx, sy, 'collect', 1);
    }
  } else if (mod === 'golden') {
    // Golden shimmer
    fill(200, 170, 50, 10 + sin(frameCount * 0.04) * 8);
    ellipse(ix, iy, c.isleRX * 2, c.isleRY * 2);
  }
  pop();
}

